import React, { useEffect, useState } from 'react';
import { get, put } from '../api';

const PendingSubmissions = () => {
  const [submissions, setSubmissions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [history, setHistory] = useState(null);
  const [historyOpenFor, setHistoryOpenFor] = useState(null);
  const [editValues, setEditValues] = useState({});

  const loadSubmissions = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin/pending-submissions');
      setSubmissions(response.data);
      const values = {};
      response.data.forEach((submission) => {
        values[submission.id] = {
          whatsAppTestStatus: submission.whatsAppTestStatus || 'Pending',
          reviewNotes: submission.reviewNotes || '',
          dispatchStatus: submission.dispatch?.deliveryStatus || 'Pending',
          docketNumber: submission.dispatch?.docketNumber || '',
          childProfileId: submission.childProfile?.id,
        };
      });
      setEditValues(values);
    } catch (err) {
      console.error(err);
      setError('Unable to fetch pending submissions.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadSubmissions();
  }, []);

  const handleDispatchUpdate = async (submissionId, dispatchStatus, docketNumber) => {
    setActionLoading(true);
    setActionError(null);
    setSuccessMessage(null);

    try {
      await put(`/api/admin/dispatch/${submissionId}`, {
        docketNumber,
        deliveryStatus: dispatchStatus,
      });
      setSuccessMessage(`Submission ${submissionId} updated successfully.`);
      await loadSubmissions();
    } catch (err) {
      console.error(err);
      setActionError('Unable to update dispatch information.');
    } finally {
      setActionLoading(false);
    }
  };

  const handleReviewNotesUpdate = async (submissionId, whatsAppStatus, reviewNotes) => {
    setActionLoading(true);
    setActionError(null);
    setSuccessMessage(null);

    try {
      await put('/api/admin/review', {
        submissionId,
        submissionStatus: 'Pending',
        whatsAppTestStatus: whatsAppStatus,
        reviewNotes,
      });
      setSuccessMessage(`Submission ${submissionId} review updated successfully.`);
      await loadSubmissions();
    } catch (err) {
      console.error(err);
      setActionError('Unable to update review notes.');
    } finally {
      setActionLoading(false);
    }
  };

  const updateEditValue = (submissionId, field, value) => {
    setEditValues((prev) => ({
      ...prev,
      [submissionId]: {
        ...prev[submissionId],
        [field]: value,
      },
    }));
  };

  const handleWhatsAppChange = async (submissionId, value) => {
    updateEditValue(submissionId, 'whatsAppTestStatus', value);
    const current = editValues[submissionId] || {};
    await handleReviewNotesUpdate(submissionId, value, current.reviewNotes || '');
  };

  const handleReviewNotesBlur = async (submissionId, value) => {
    updateEditValue(submissionId, 'reviewNotes', value);
    const current = editValues[submissionId] || {};
    await handleReviewNotesUpdate(submissionId, current.whatsAppTestStatus || 'Pending', value);
  };

  const handleDispatchStatusChange = async (submissionId, value) => {
    updateEditValue(submissionId, 'dispatchStatus', value);
    const current = editValues[submissionId] || {};
    await handleDispatchUpdate(submissionId, value, current.docketNumber || '');
  };

  const handleDocketBlur = async (submissionId, value) => {
    updateEditValue(submissionId, 'docketNumber', value);
    const current = editValues[submissionId] || {};
    await handleDispatchUpdate(submissionId, current.dispatchStatus || 'Pending', value);
  };

  const renderParentInfo = (submission) => {
    if (!submission.parent) {
      return 'Unknown';
    }
    return submission.parent.phone
      ? `${submission.parent.phone} #${submission.parent.id}`
      : `#${submission.parent.id}`;
  };

  const handleShowHistory = async (childProfileId) => {
    setActionLoading(true);
    setActionError(null);
    setSuccessMessage(null);

    try {
      const response = await get(`/api/admin/submission-history/${childProfileId}`);
      setHistory(response.data);
      setHistoryOpenFor(childProfileId);
    } catch (err) {
      console.error(err);
      setActionError('Unable to load submission history.');
    } finally {
      setActionLoading(false);
    }
  };

  const handleRefresh = () => {
    loadSubmissions();
  };

  return (
    <div>
      <h2>Pending Submissions</h2>
      <div style={{ marginBottom: 12 }}>
        <button onClick={handleRefresh} disabled={loading}>
          Refresh
        </button>
      </div>
      {loading && <p>Loading submissions...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {!loading && !error && submissions.length === 0 && <p>No pending submissions.</p>}
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}
      {!loading && !error && submissions.length > 0 && (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Submission</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Parent</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Child</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Address</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Rhyme</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Gift</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>WhatsApp Status</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Review Notes</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Dispatch Status</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Docket</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {submissions.map((submission) => (
              <tr key={submission.id}>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{submission.id}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {renderParentInfo(submission)}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {submission.childProfile?.name || 'Unknown'}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {submission.address || 'Unknown'}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {submission.rhyme?.title || 'Unknown'}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  {submission.gift?.name || 'Unknown'}
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <select
                    value={editValues[submission.id]?.whatsAppTestStatus || submission.whatsAppTestStatus || 'Pending'}
                    onChange={(e) => handleWhatsAppChange(submission.id, e.target.value)}
                    disabled={actionLoading}
                    style={{ width: '100%' }}
                  >
                    <option value="Pending">Pending</option>
                    <option value="Passed">Passed</option>
                    <option value="Postponed">Postponed</option>
                  </select>
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <textarea
                    value={editValues[submission.id]?.reviewNotes ?? submission.reviewNotes ?? ''}
                    onChange={(e) => updateEditValue(submission.id, 'reviewNotes', e.target.value)}
                    onBlur={(e) => handleReviewNotesBlur(submission.id, e.target.value)}
                    disabled={actionLoading}
                    rows={2}
                    style={{ width: '100%' }}
                  />
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <select
                    value={editValues[submission.id]?.dispatchStatus || submission.dispatch?.deliveryStatus || 'Pending'}
                    onChange={(e) => handleDispatchStatusChange(submission.id, e.target.value)}
                    disabled={actionLoading}
                    style={{ width: '100%' }}
                  >
                    <option value="Pending">Pending</option>
                    <option value="Dispatched">Dispatched</option>
                    <option value="Delivered">Delivered</option>
                    <option value="Returned">Returned</option>
                  </select>
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <input
                    value={editValues[submission.id]?.docketNumber ?? submission.dispatch?.docketNumber ?? ''}
                    onChange={(e) => updateEditValue(submission.id, 'docketNumber', e.target.value)}
                    onBlur={(e) => handleDocketBlur(submission.id, e.target.value)}
                    disabled={actionLoading}
                    style={{ width: '100%' }}
                  />
                </td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <button
                    disabled={actionLoading || !submission.childProfile?.id}
                    onClick={() => handleShowHistory(submission.childProfile?.id)}
                  >
                    History
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
      {historyOpenFor && history && (
        <div style={{ marginTop: '24px' }}>
          <h3>Submission History for Child #{historyOpenFor}</h3>
          {history.length === 0 ? (
            <p>No history available.</p>
          ) : (
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Submission</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Rhyme</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Gift</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Address</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Status</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Dispatch</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Docket</th>
                  <th style={{ border: '1px solid #ccc', padding: '8px' }}>Created At</th>
                </tr>
              </thead>
              <tbody>
                {history.map((item) => (
                  <tr key={item.id}>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.id}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.rhyme || 'Unknown'}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.gift || 'Unknown'}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.address || 'Unknown'}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.status}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.dispatchStatus}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{item.docket || 'None'}</td>
                    <td style={{ border: '1px solid #ccc', padding: '8px' }}>{new Date(item.createdAt).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
};

export default PendingSubmissions;
